import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { adminService } from '../../services/api';
import AdminRoundScheduling from './AdminRoundScheduling';

const styles = `
  @keyframes slideUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
  }
`;

const STATUS_CFG = {
  APPLIED: { label: 'Applied', cls: 'badge-applied' },
  APTITUDE_SCHEDULED: { label: 'Aptitude Scheduled', cls: 'badge-review' },
  APTITUDE_CLEARED: { label: 'Aptitude Cleared', cls: 'badge-approved' },
  APTITUDE_FAILED: { label: 'Aptitude Failed', cls: 'badge-rejected' },
  INTERVIEW_SCHEDULED: { label: 'Interview Scheduled', cls: 'badge-shortlisted' },
  SELECTED: { label: 'Selected', cls: 'badge-selected' },
  REJECTED: { label: 'Rejected', cls: 'badge-rejected' },
};

const DEPT_ABBR = {
  'Computer Science & Engineering': 'CSE',
  'Electronics & Communication': 'ECE',
  'Mechanical Engineering': 'ME',
  'Civil Engineering': 'CE',
  'Electrical Engineering': 'EE',
  'Information Technology': 'IT',
  'Master of Computer Applications': 'MCA',
};

const getDeptFullName = deptAbbr => {
  if (!deptAbbr) return '--';
  const normalizedDept = `${deptAbbr}`.trim().toLowerCase();
  return Object.entries(DEPT_ABBR).find(([, abbr]) => abbr.toLowerCase() === normalizedDept)?.[0] || deptAbbr;
};

export default function AdminJobApplicants() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [applicants, setApplicants] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);
  const [showStudentModal, setShowStudentModal] = useState(false);
  const [studentProfile, setStudentProfile] = useState(null);
  const [profileLoading, setProfileLoading] = useState(false);
  const [showRoundScheduling, setShowRoundScheduling] = useState(false);
  const [showIntModal, setShowIntModal] = useState(false);
  const [showAptModal, setShowAptModal] = useState(false);
  const [showResultModal, setShowResultModal] = useState(false);
  const [actionApp, setActionApp] = useState(null);
  const [intForm, setIntForm] = useState({ interviewDate: '', interviewTime: '', interviewMode: 'Online' });
  const [aptForm, setAptForm] = useState({ cleared: true, score: '' });
  const [resultForm, setResultForm] = useState({ result: 'Pass', notes: '', finalSelected: true });
  const [saving, setSaving] = useState(false);

  const fetchData = () => {
    setLoading(true);
    adminService.getApplicants(id)
      .then(response => {
        setApplicants(response.data);
        setSelected(prev => response.data.find(app => app.id === prev?.id) || null);
      })
      .catch(error => {
        console.error(error);
        toast.error(error.response?.data?.message || 'Failed to load applicants.');
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    const styleSheet = document.createElement('style');
    styleSheet.textContent = styles;
    document.head.appendChild(styleSheet);
    return () => styleSheet.remove();
  }, []);

  useEffect(() => {
    fetchData();
  }, [id]);

  const fetchStudentProfile = async userId => {
    if (!userId) return;
    setProfileLoading(true);
    try {
      const { data } = await adminService.getStudent(userId);
      setStudentProfile(data);
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || 'Failed to load full profile.');
    } finally {
      setProfileLoading(false);
    }
  };

  const doScheduleAptitude = async appId => {
    try {
      await adminService.scheduleAptitude(appId);
      toast.success('Aptitude scheduled.');
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed.');
    }
  };

  const doAptitudeResult = async event => {
    event.preventDefault();
    setSaving(true);
    try {
      const clearedBool = aptForm.cleared === 'true' || aptForm.cleared === true;
      await adminService.aptitudeResult(actionApp.id, {
        cleared: clearedBool,
        score: aptForm.score ? parseInt(aptForm.score, 10) : null,
      });
      toast.success('Aptitude result recorded.');
      setShowAptModal(false);
      fetchData();
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || 'Failed.');
    } finally {
      setSaving(false);
    }
  };

  const doScheduleInterview = async event => {
    event.preventDefault();
    setSaving(true);
    try {
      await adminService.scheduleInterview(actionApp.id, intForm);
      toast.success('Interview scheduled.');
      setShowIntModal(false);
      fetchData();
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || 'Failed.');
    } finally {
      setSaving(false);
    }
  };

  const doInterviewResult = async event => {
    event.preventDefault();
    setSaving(true);
    try {
      const finalSelectedBool = resultForm.finalSelected === 'true' || resultForm.finalSelected === true;
      await adminService.interviewResult(actionApp.id, {
        result: resultForm.result,
        notes: resultForm.notes,
        finalSelected: finalSelectedBool,
      });
      toast.success('Result recorded.');
      setShowResultModal(false);
      fetchData();
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || 'Failed.');
    } finally {
      setSaving(false);
    }
  };

  const doRejectApplicant = async app => {
    if (!window.confirm(`Reject ${app.studentName} from this selection process?`)) return;
    try {
      await adminService.rejectApplicant(app.id);
      toast.success('Applicant rejected.');
      fetchData();
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || 'Failed to reject applicant.');
    }
  };

  const openModal = (app, type) => {
    setActionApp(app);
    if (type === 'aptitude') setShowAptModal(true);
    else if (type === 'interview') setShowIntModal(true);
    else setShowResultModal(true);
  };

  const openStudentModal = async app => {
    setShowStudentModal(true);
    setStudentProfile(null);
    await fetchStudentProfile(app.userId);
  };

  const closeStudentModal = () => {
    setShowStudentModal(false);
    setStudentProfile(null);
  };

  const downloadApplicantResume = async student => {
    if (!student?.hasResume) {
      toast.error('Resume not available.');
      return;
    }

    try {
      const { data } = await adminService.downloadResume(student.id);
      const url = URL.createObjectURL(new Blob([data]));
      const anchor = document.createElement('a');
      anchor.href = url;
      anchor.download = student.resume?.originalFileName || 'resume';
      anchor.click();
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || 'Resume download failed.');
    }
  };

  const renderApplicantActions = app => (
    <div style={{ display: 'flex', gap: 5, flexWrap: 'wrap' }}>
      {app.status === 'APPLIED' && <button className="btn btn-sm btn-info" onClick={() => doScheduleAptitude(app.id)}>Schedule Aptitude</button>}
      {app.status === 'APTITUDE_SCHEDULED' && <button className="btn btn-sm btn-outline" onClick={() => openModal(app, 'aptitude')}>Record Result</button>}
      {app.status === 'APTITUDE_CLEARED' && <button className="btn btn-sm btn-primary" onClick={() => openModal(app, 'interview')}>Schedule Interview</button>}
      {app.status === 'INTERVIEW_SCHEDULED' && <button className="btn btn-sm btn-gold" onClick={() => openModal(app, 'result')}>Record Result</button>}
      {!['SELECTED', 'REJECTED'].includes(app.status) && <button className="btn btn-sm btn-danger" onClick={() => doRejectApplicant(app)}>Reject</button>}
      {['SELECTED', 'REJECTED'].includes(app.status) && <span style={{ fontSize: 12, color: 'var(--gray-400)' }}>Completed</span>}
    </div>
  );

  return (
    <>
      <div className="topbar">
        <div>
          <button
            onClick={() => navigate('/admin/jobs')}
            style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--gold)', fontSize: 13, marginBottom: 4 }}
          >
            Back to Jobs
          </button>
          <div className="topbar-title">Job Applicants</div>
          <div className="topbar-sub">{applicants.length} applicant{applicants.length !== 1 ? 's' : ''} for this position</div>
        </div>
      </div>

      <div className="page-content">
        <div style={{ display: 'grid', gridTemplateColumns: selected ? '1fr 380px' : '1fr', gap: 20, alignItems: 'start' }}>
          <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>Student</th>
                    <th>Dept</th>
                    <th>CGPA</th>
                    <th>Applied</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {loading && (
                    <tr>
                      <td colSpan={6} style={{ textAlign: 'center', padding: 32, color: 'var(--gray-400)' }}>
                        Loading...
                      </td>
                    </tr>
                  )}
                  {!loading && applicants.length === 0 && (
                    <tr>
                      <td colSpan={6} style={{ textAlign: 'center', padding: 32, color: 'var(--gray-400)' }}>
                        No applicants yet.
                      </td>
                    </tr>
                  )}
                  {applicants.map(applicant => {
                    const statusConfig = STATUS_CFG[applicant.status] || { label: applicant.status, cls: 'badge-pending' };
                    return (
                      <tr
                        key={applicant.id}
                        style={{ cursor: 'pointer', background: selected?.id === applicant.id ? 'var(--off-white)' : '' }}
                        onClick={() => setSelected(selected?.id === applicant.id ? null : applicant)}
                      >
                        <td>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                            <div className="avatar avatar-sm">{applicant.studentName?.[0]}</div>
                            <div>
                              <div style={{ fontWeight: 500, fontSize: 13 }}>{applicant.studentName}</div>
                              <div style={{ fontSize: 11, color: 'var(--gray-400)' }}>{applicant.studentEmail}</div>
                            </div>
                          </div>
                        </td>
                        <td style={{ fontSize: 12 }}>{getDeptFullName(applicant.department)}</td>
                        <td style={{ fontWeight: 600 }}>{applicant.cgpa || '--'}</td>
                        <td style={{ fontSize: 12, color: 'var(--gray-400)' }}>
                          {new Date(applicant.appliedAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}
                        </td>
                        <td><span className={`badge ${statusConfig.cls}`}>{statusConfig.label}</span></td>
                        <td onClick={event => event.stopPropagation()}>{renderApplicantActions(applicant)}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {selected && (
            <div className="card" style={{ position: 'sticky', top: 80 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
                <div style={{ fontWeight: 600, fontSize: 15, color: 'var(--navy)' }}>{selected.studentName}</div>
                <button onClick={() => setSelected(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--gray-400)', fontSize: 18 }}>
                  x
                </button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10, fontSize: 13 }}>
                {[
                  ['Email', selected.studentEmail],
                  ['Roll No.', selected.rollNumber],
                  ['Department', getDeptFullName(selected.department)],
                  ['CGPA', selected.cgpa || '--'],
                  ['Status', <span className={`badge ${(STATUS_CFG[selected.status] || {}).cls}`}>{(STATUS_CFG[selected.status] || {}).label}</span>],
                  selected.aptitudeScore != null && ['Aptitude', `Score: ${selected.aptitudeScore} - ${selected.aptitudeCleared ? 'Cleared' : 'Failed'}`],
                  selected.interviewDate && ['Interview', `${selected.interviewDate} ${selected.interviewTime} (${selected.interviewMode})`],
                  selected.interviewResult && ['Int. Result', selected.interviewResult],
                  selected.interviewNotes && ['Notes', selected.interviewNotes],
                  selected.finalSelected != null && ['Final', selected.finalSelected ? 'Selected' : 'Not Selected'],
                ].filter(Boolean).map(([key, value]) => (
                  <div key={key} style={{ display: 'flex', gap: 8, borderBottom: '1px solid var(--gray-100)', paddingBottom: 8 }}>
                    <span style={{ color: 'var(--gray-400)', minWidth: 90, flexShrink: 0 }}>{key}</span>
                    <span style={{ fontWeight: 500 }}>{value}</span>
                  </div>
                ))}
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 16 }}>
                {selected.status === 'APPLIED' && <button className="btn btn-info btn-full" onClick={() => doScheduleAptitude(selected.id)}>Schedule Aptitude Test</button>}
                {selected.status === 'APTITUDE_SCHEDULED' && <button className="btn btn-outline btn-full" onClick={() => openModal(selected, 'aptitude')}>Record Aptitude Result</button>}
                {selected.status === 'APTITUDE_CLEARED' && <button className="btn btn-primary btn-full" onClick={() => openModal(selected, 'interview')}>Schedule Interview</button>}
                {selected.status === 'INTERVIEW_SCHEDULED' && <button className="btn btn-gold btn-full" onClick={() => openModal(selected, 'result')}>Record Interview Result</button>}
                {['APTITUDE_CLEARED', 'INTERVIEW_SCHEDULED', 'SELECTED', 'REJECTED'].includes(selected.status) && (
                  <button className="btn btn-success btn-full" onClick={() => setShowRoundScheduling(true)}>Round Scheduling</button>
                )}
                {!['SELECTED', 'REJECTED'].includes(selected.status) && (
                  <button className="btn btn-danger btn-full" onClick={() => doRejectApplicant(selected)}>Reject Applicant</button>
                )}
                <button className="btn btn-outline btn-full" onClick={() => openStudentModal(selected)}>View Full Profile</button>
              </div>
            </div>
          )}
        </div>
      </div>

      {showAptModal && (
        <div className="modal-overlay" onClick={() => setShowAptModal(false)}>
          <div className="modal" onClick={event => event.stopPropagation()}>
            <h3 className="modal-title">Record Aptitude Result - {actionApp?.studentName}</h3>
            <form onSubmit={doAptitudeResult}>
              <div className="form-group">
                <label>Result</label>
                <select value={aptForm.cleared} onChange={event => setAptForm(prev => ({ ...prev, cleared: event.target.value }))}>
                  <option value="true">Cleared</option>
                  <option value="false">Failed</option>
                </select>
              </div>
              <div className="form-group">
                <label>Score (Optional)</label>
                <input type="number" placeholder="e.g. 75" value={aptForm.score} onChange={event => setAptForm(prev => ({ ...prev, score: event.target.value }))} />
              </div>
              <div className="btn-row">
                <button type="button" className="btn btn-outline" onClick={() => setShowAptModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : 'Save Result'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showIntModal && (
        <div className="modal-overlay" onClick={() => setShowIntModal(false)}>
          <div className="modal" onClick={event => event.stopPropagation()}>
            <h3 className="modal-title">Schedule Interview - {actionApp?.studentName}</h3>
            <form onSubmit={doScheduleInterview}>
              <div className="form-row">
                <div className="form-group">
                  <label>Date *</label>
                  <input type="date" required value={intForm.interviewDate} onChange={event => setIntForm(prev => ({ ...prev, interviewDate: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Time *</label>
                  <input type="time" required value={intForm.interviewTime} onChange={event => setIntForm(prev => ({ ...prev, interviewTime: event.target.value }))} />
                </div>
              </div>
              <div className="form-group">
                <label>Mode</label>
                <select value={intForm.interviewMode} onChange={event => setIntForm(prev => ({ ...prev, interviewMode: event.target.value }))}>
                  <option>Online</option>
                  <option>In-person</option>
                  <option>Phone</option>
                </select>
              </div>
              <div className="btn-row">
                <button type="button" className="btn btn-outline" onClick={() => setShowIntModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Scheduling...' : 'Schedule'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showResultModal && (
        <div className="modal-overlay" onClick={() => setShowResultModal(false)}>
          <div className="modal" onClick={event => event.stopPropagation()}>
            <h3 className="modal-title">Interview Result - {actionApp?.studentName}</h3>
            <form onSubmit={doInterviewResult}>
              <div className="form-group">
                <label>Interview Result</label>
                <select value={resultForm.result} onChange={event => setResultForm(prev => ({ ...prev, result: event.target.value }))}>
                  <option>Pass</option>
                  <option>Fail</option>
                  <option>On Hold</option>
                </select>
              </div>
              <div className="form-group">
                <label>Final Selection Decision</label>
                <select value={resultForm.finalSelected} onChange={event => setResultForm(prev => ({ ...prev, finalSelected: event.target.value }))}>
                  <option value="true">Selected</option>
                  <option value="false">Not Selected</option>
                </select>
              </div>
              <div className="form-group">
                <label>Notes (Optional)</label>
                <textarea rows={3} placeholder="Feedback or remarks..." value={resultForm.notes} onChange={event => setResultForm(prev => ({ ...prev, notes: event.target.value }))} />
              </div>
              <div className="btn-row">
                <button type="button" className="btn btn-outline" onClick={() => setShowResultModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-gold" disabled={saving}>{saving ? 'Saving...' : 'Save Result'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showStudentModal && selected && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.5)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
          }}
          onClick={closeStudentModal}
        >
          <div
            style={{
              background: 'white',
              borderRadius: '12px',
              boxShadow: '0 10px 40px rgba(0,0,0,0.2)',
              maxWidth: 720,
              width: '92%',
              maxHeight: '85vh',
              overflow: 'auto',
              animation: 'slideUp 0.3s ease',
            }}
            onClick={event => event.stopPropagation()}
          >
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                padding: '20px 24px',
                borderBottom: '1px solid var(--gray-200)',
              }}
            >
              <div>
                <h2 style={{ margin: 0, fontSize: 20, fontWeight: 600, color: 'var(--text)' }}>
                  {studentProfile ? `${studentProfile.firstName} ${studentProfile.lastName}` : selected.studentName}
                </h2>
                <p style={{ margin: '4px 0 0 0', fontSize: 13, color: 'var(--gray-400)' }}>
                  {studentProfile?.email || selected.studentEmail}
                </p>
              </div>
              <button
                onClick={closeStudentModal}
                style={{
                  background: 'none',
                  border: 'none',
                  fontSize: 24,
                  color: 'var(--gray-400)',
                  cursor: 'pointer',
                  padding: 0,
                  width: 32,
                  height: 32,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                x
              </button>
            </div>

            <div style={{ padding: '24px' }}>
              {profileLoading ? (
                <div style={{ textAlign: 'center', padding: '24px 0', color: 'var(--gray-400)' }}>Loading full profile...</div>
              ) : (
                <>
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: 20 }}>
                    {[
                      ['Roll Number', studentProfile?.rollNumber || selected.rollNumber || '--'],
                      ['Department', getDeptFullName(studentProfile?.department || selected.department)],
                      ['Batch Year', studentProfile?.batchYear || '--'],
                      ['CGPA', studentProfile?.cgpa || selected.cgpa || '--'],
                      ['Phone', studentProfile?.phone || '--'],
                      ['Gender', studentProfile?.gender || '--'],
                    ].map(([label, value]) => (
                      <div key={label}>
                        <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>{label}</label>
                        <div style={{ fontSize: 14, color: 'var(--text)', marginTop: 4 }}>{value}</div>
                      </div>
                    ))}
                  </div>

                  <div style={{ borderTop: '1px solid var(--gray-200)', paddingTop: 20, marginBottom: 20 }}>
                    <h3 style={{ fontSize: 13, fontWeight: 600, color: 'var(--text)', textTransform: 'uppercase', margin: '0 0 16px 0' }}>Professional Profile</h3>
                    <div style={{ marginBottom: 16 }}>
                      <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>Skills</label>
                      <div style={{ fontSize: 14, color: 'var(--text)', marginTop: 4, lineHeight: 1.6 }}>{studentProfile?.skills || '--'}</div>
                    </div>
                    <div style={{ marginBottom: 16 }}>
                      <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>LinkedIn URL</label>
                      <div style={{ fontSize: 14, marginTop: 4 }}>
                        {studentProfile?.linkedinUrl ? (
                          <a href={studentProfile.linkedinUrl} target="_blank" rel="noopener noreferrer" style={{ color: 'var(--navy)', textDecoration: 'none' }}>
                            {studentProfile.linkedinUrl}
                          </a>
                        ) : '--'}
                      </div>
                    </div>
                    <div>
                      <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>Cover Note</label>
                      <div style={{ fontSize: 14, color: 'var(--text)', marginTop: 4, whiteSpace: 'pre-wrap', lineHeight: 1.6 }}>
                        {studentProfile?.coverNote || '--'}
                      </div>
                    </div>
                  </div>

                  <div style={{ borderTop: '1px solid var(--gray-200)', paddingTop: 20, marginBottom: 20 }}>
                    <h3 style={{ fontSize: 13, fontWeight: 600, color: 'var(--text)', textTransform: 'uppercase', margin: '0 0 16px 0' }}>Resume</h3>
                    {studentProfile?.hasResume ? (
                      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, background: 'var(--off-white)', borderRadius: 10, padding: 14 }}>
                        <div>
                          <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text)' }}>{studentProfile.resume?.originalFileName || 'Resume'}</div>
                          <div style={{ fontSize: 12, color: 'var(--gray-400)', marginTop: 2 }}>{studentProfile.resume?.fileType || 'Document'}</div>
                        </div>
                        <button className="btn btn-primary btn-sm" onClick={() => downloadApplicantResume(studentProfile)}>Download Resume</button>
                      </div>
                    ) : (
                      <div style={{ fontSize: 14, color: 'var(--gray-400)' }}>Resume not uploaded.</div>
                    )}
                  </div>

                  <div style={{ borderTop: '1px solid var(--gray-200)', paddingTop: 20 }}>
                    <h3 style={{ fontSize: 13, fontWeight: 600, color: 'var(--text)', textTransform: 'uppercase', margin: '0 0 16px 0' }}>Application Status</h3>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 12, fontSize: 13 }}>
                      {[
                        ['Status', <span className={`badge ${(STATUS_CFG[selected.status] || {}).cls}`}>{(STATUS_CFG[selected.status] || {}).label}</span>],
                        ['Applied', new Date(selected.appliedAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })],
                        selected.aptitudeScore != null && ['Aptitude Score', `${selected.aptitudeScore} - ${selected.aptitudeCleared ? 'Cleared' : 'Failed'}`],
                        selected.interviewDate && ['Interview Date', selected.interviewDate],
                        selected.interviewTime && ['Interview Time', selected.interviewTime],
                        selected.interviewMode && ['Interview Mode', selected.interviewMode],
                        selected.interviewResult && ['Interview Result', selected.interviewResult],
                        selected.interviewNotes && ['Notes', selected.interviewNotes],
                        selected.finalSelected != null && ['Final Decision', selected.finalSelected ? 'Selected' : 'Not Selected'],
                      ].filter(Boolean).map(([key, value]) => (
                        <div key={key} style={{ display: 'flex', gap: 8, borderBottom: '1px solid var(--gray-100)', paddingBottom: 10 }}>
                          <span style={{ color: 'var(--gray-400)', minWidth: 110, flexShrink: 0 }}>{key}</span>
                          <span style={{ color: 'var(--text-mid)', fontWeight: 500 }}>{value}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {showRoundScheduling && selected && (
        <div className="modal-overlay" onClick={() => setShowRoundScheduling(false)}>
          <div className="modal" style={{ maxWidth: 700, maxHeight: '80vh', overflow: 'auto' }} onClick={event => event.stopPropagation()}>
            <AdminRoundScheduling appId={selected.id} onBack={() => { setShowRoundScheduling(false); fetchData(); }} />
          </div>
        </div>
      )}
    </>
  );
}
